oid.R.attr.state_checked},			{},		},	    {			0xff6867AA,			0x55DFDFDF		})local swcThumb=ColorStateList({			{android.R.attr.state_checked},			{android.R.attr.state_pressed},			{-android.R.attr.state_pressed},		}, {			0xFFFFFFFF,			0xFFFFFFFF,			0xFFFFFFFF		})  check={    LinearLayout,    layout_width='match_parent',    layout_height="42dp",    layout_weight=1,    layout_marginTop="1dp",    layout_marginBottom="1dp",    {			SwitchButton,			ThumbRadius = "90dp",			BackRadius = "90dp",			ThumbRangeRatio = '0.9dp',			ThumbMargin = RectF(5,5,5,5),			id=luajava.newId(nid),			__onFinish=function(v)			v:setThumbColor(swcThumb)			v:setBackColor(swcDraw)				luajava.setInterface(v, "setOnCheckedChangeListener", 					{onCheckedChanged=function(view,isc)						if isc then          luajava.newThread(function()            pcall(func1)          end):start()         else          luajava.newThread(function()            pcall(func2)          end):start()        end					end})			end,			layout_width = "45dp",			layout_height = "20dp",		},		{		TextView,		text = name,		layout_height = "20dp",		gravity = "center",		textColor = 0xFFFFFFFF,		}  }  return checkend  function Yunzhu.check(cklist)  if #cklist==0 then return nil end  local rest={    LinearLayout,    layout_width='fill_parent',    layout_height="wrap_content",    layout_marginRight="4dp",    layout_marginLeft="4dp",    layout_marginTop="3.5dp",    layout_marginBottom="3.5dp",    gravity="center",    orientation="vertical",  }  for i=1,#cklist,2 do    local tempTable={LinearLayout,      layout_width='fill_parent',      layout_height="wrap_content",      gravity="left",      orientation="horizontal"    }    for j=0,1 do      if cklist[i + j] ~=nil then        local name=cklist[i + j][1]        local func1=cklist[i + j][2]        local func2=cklist[i + j][3]        if not name then name="未设置" end        rstt=Yunzhu.intcheck(name,func1,func2)        table.insert(tempTable,rstt)       else        table.insert(tempTable,{LinearLayout,          layout_width='match_parent',          layout_weight=1,})      end    end    table.insert(rest,tempTable)  end  return restendend项目名称 = "Imgui"stab = {	'page',	'page',	'page'}高度 = 500宽度 = 900Initialization()--页面必须和菜单数一样多，不然报错Yunzhu.menu({	{		Yunzhu.check({      {        "Yunzhu",        function()        end,        function()        end        }, {        "Yunzhu",        function()        end,        function()        end        }, {        "Ar4m96ani",        function()        end,        function()        end      },    }),	},	{		Yunzhu.check({      {        "例子",        function()        end,        function()        end        }, {        "例子",        function()        end,        function()        end        }, {        "测试1",        function()        end,        function()        end      },    }),	},	{		Yunzhu.check({      {        "退出",        function()        tuichu = 1        end,        function()        end        }, {        "例子",        function()        end,        function()        end        }, {        "测试1",        function()        end,        function()        end      },    }),	}})while true do	if tuichu==1 then 		break	endend